CustomFunction.Calculation:
// Executes SELECT COUNT(*) for the assembled query and returns the count as a number.
// The original query object is not modified.
// Returns 0 on error or empty result.
Let
(
[
_q = JSONSetElement ( query ; "selects" ; "COUNT(*)" ; JSONString ) ;
_result = QueryGet ( _q ; ¶ ; Char ( 28 ) )
];
GetAsNumber ( GetValue ( _result ; 1 ) )
)
